mapper.sql:
WHERE 1 = 1

    AND notice_type = #{type}


    AND notice_pin_yn = #{pinnedYn}


    AND notice_use_yn = #{useYn}


    AND (
        UPPER(notice_title) LIKE '%' || UPPER(#{keyword}) || '%'
        OR UPPER(notice_content) LIKE '%' || UPPER(#{keyword}) || '%'
    )


    AND TRUNC(notice_adddate) >= TO_DATE(#{fromDate}, 'YYYY-MM-DD')


    AND TRUNC(notice_adddate) <= TO_DATE(#{toDate}, 'YYYY-MM-DD')

mapper.update:
UPDATE notice
SET notice_cnt = NVL(notice_cnt, 0) + 1
WHERE notice_no = #{noticeNo}

mapper.insert:

    SELECT NVL(MAX(notice_no), 0) + 1 FROM notice

INSERT INTO notice (
    notice_no
  , notice_type
  , notice_title
  , notice_content
  , notice_adddate
  , notice_upddate
  , notice_cnt
  , notice_admin_id
  , notice_pin_yn
  , notice_use_yn
) VALUES (
    #{noticeNo}
  , #{noticeType}
  , #{noticeTitle}
  , #{noticeContent}
  , SYSDATE
  , SYSDATE
  , 0
  , #{noticeAdminId}
  , #{noticePinYn}
  , #{noticeUseYn}
)

mapper.update:
UPDATE notice
SET
    notice_type = #{noticeType}
  , notice_title = #{noticeTitle}
  , notice_content = #{noticeContent}
  , notice_use_yn = #{noticeUseYn}
  , notice_upddate = SYSDATE
WHERE notice_no = #{noticeNo}

UPDATE notice
SET notice_pin_yn = #{noticePinYn}
  , notice_upddate = SYSDATE
WHERE notice_no = #{noticeNo}

UPDATE notice
SET notice_use_yn = #{noticeUseYn}
  , notice_upddate = SYSDATE
WHERE notice_no = #{noticeNo}
